class ListElement(MarkdownElement):
    """A list element."""

    @classmethod
    def create(cls, markdown: Markdown, token: Token) -> ListElement:
        return cls(token.type, int(token.attrs.get("start", 1)))

    def __init__(self, list_type: str, list_start: int | None) -> None:
        self.items: list[ListItem] = []
        self.list_type = list_type
        self.list_start = list_start

    def on_child_close(self, context: MarkdownContext, child: MarkdownElement) -> bool:
        assert isinstance(child, ListItem)
        self.items.append(child)
        return False

    def __rich_console__(
        self, console: Console, options: ConsoleOptions
    ) -> RenderResult:
        if self.list_type == "bullet_list_open":
            for item in self.items:
                yield from item.render_bullet(console, options)
        else:
            number = 1 if self.list_start is None else self.list_start
            last_number = number + len(self.items)
            for index, item in enumerate(self.items):
                yield from item.render_number(
                    console, options, number + index, last_number
                )

class ListElement(MarkdownElement) {
  @classmethod create(markdown:Markdown, token:Token)->ListElement = 
    cls(token.type, int(token.attrs.get("start",1)))

  __init__(list_type:str, list_start:int|None) {
    items:list[ListItem] = []
    list_type = list_type
    list_start = list_start
  }

  on_child_close(context:MarkdownContext, child:MarkdownElement)->bool = 
    assert isinstance(child, ListItem) |> items.append(child) |> False

  __rich_console__(console:Console, options:ConsoleOptions)->RenderResult = 
    list_type=="bullet_list_open" ? 
      [item.render_bullet(console,options) for item in items] :
      [item.render_number(console,options, 1+index, 1+len(items)+index) 
       for index,item in enumerate(items)]
}
